urlset:

    {{ site.url }}/
    {{ now.strftime('%Y-%m-%d') }}
    daily
    1.0


    {{ site.url }}/artykuly.html
    {{ now.strftime('%Y-%m-%d') }}
    daily
    0.9

{% for a in articles %}

    {{ site.url }}/artykuly/{{ a.slug }}.html
    {{ (a.updated_at or a.published_at or a.created_at)[:10] }}
    monthly
    0.8
    {% if a.image_url %}

        {{ a.image_url if 'http' in a.image_url else site.url + a.image_url }}
        {{ a.title | e }}
        {{ a.excerpt | e }}

    {% endif %}

{% endfor %}
{% for c in categories %}

    {{ site.url }}/kategoria/{{ c.slug }}.html
    {{ now.strftime('%Y-%m-%d') }}
    weekly
    0.7

{% endfor %}
{% for au in authors %}

    {{ site.url }}/autor/{{ au.slug }}.html
    monthly
    0.6

{% endfor %}

    {{ site.url }}/polityka-prywatnosci.html
    yearly
    0.3


    {{ site.url }}/regulamin.html
    yearly
    0.3
